var oClonedGamesRound=new Object();{for(var nI in oClonedGamesPerPoule){for(var nJ in oClonedGamesPerPoule[nI]){var oClonedGame=oClonedGamesPerPoule[nI][nJ];oClonedGamesRound[oClonedGame.getId()]=oClonedGame}}}
